def _safe_mkdir(path: str) -> None:
    os.makedirs(path, exist_ok=True)


def _check_upload_size(content: bytes) -> None:
    max_bytes = DEFAULT_MAX_UPLOAD_MB * 1024 * 1024
    if len(content) > max_bytes:
        raise HTTPException(status_code=413, detail=f"Upload too large. Max {DEFAULT_MAX_UPLOAD_MB} MB.")


def _read_upload_bytes(file: UploadFile) -> bytes:
    data = file.file.read()
    _check_upload_size(data)
    return data


def _is_image_path(p: str) -> bool:
    ext = os.path.splitext(p)[1].lower()
    return ext in ALLOWED_IMAGE_EXTS


def _resolve_path(base_dir: str, p: str) -> str:
    p = p.strip()
    if not p:
        raise ValueError("Empty path")
    if p.startswith(("http://", "https://")):
        raise ValueError("URL images not supported. Upload images or zip bundle instead.")
    ap = os.path.abspath(os.path.join(base_dir, p))
    if not ap.startswith(os.path.abspath(base_dir) + os.sep) and ap != os.path.abspath(base_dir):
        raise ValueError("Path traversal detected")
    return ap


def _save_bytes(path: str, data: bytes) -> None:
    _safe_mkdir(os.path.dirname(path))
    with open(path, "wb") as f:
        f.write(data)


def _extract_zip_to_dir(zip_bytes: bytes, out_dir: str) -> None:
    _safe_mkdir(out_dir)
    with zipfile.ZipFile(io.BytesIO(zip_bytes), "r") as zf:
        for m in zf.infolist():
            name = m.filename
            if name.endswith("/"):
                continue
            if name.startswith("/") or ".." in name.replace("\\", "/").split("/"):
                raise HTTPException(status_code=400, detail="Invalid zip content (path traversal).")
            dest = os.path.abspath(os.path.join(out_dir, name))
            if not dest.startswith(os.path.abspath(out_dir) + os.sep) and dest != os.path.abspath(out_dir):
                raise HTTPException(status_code=400, detail="Invalid zip content (path traversal).")
            _safe_mkdir(os.path.dirname(dest))
            with zf.open(m, "r") as src, open(dest, "wb") as dst:
                shutil.copyfileobj(src, dst)


def _load_csv(csv_path: str) -> pd.DataFrame:
    df = pd.read_csv(csv_path)
    df.columns = [c.strip() for c in df.columns]
    required = {"image_path", "label"}
    if not required.issubset(set(df.columns)):
        raise HTTPException(status_code=400, detail="CSV must include columns: image_path,label")
    df = df[["image_path", "label"]].copy()
    df["image_path"] = df["image_path"].astype(str)
    df["label"] = df["label"].astype(str)
    df = df.dropna()
    df = df[df["image_path"].str.len() > 0]
    df = df[df["label"].str.len() > 0]
    return df


def _train_val_test_split(n: int, val_split: float, test_split: float, seed: int) -> List[str]:
    rng = np.random.RandomState(seed)
    idx = np.arange(n)
    rng.shuffle(idx)
    splits = np.array(["train"] * n, dtype=object)
    n_test = int(round(n * test_split))
    n_val = int(round(n * val_split))
    if n_test > 0:
        splits[idx[:n_test]] = "test"
    if n_val > 0:
        splits[idx[n_test : n_test + n_val]] = "val"
    return splits.tolist()


def _ingest_contribution(contribution_id: str, csv_path: str, bundle_dir: str) -> Tuple[int, int, int]:
    df = _load_csv(csv_path)
    splits = _train_val_test_split(len(df), DEFAULT_VALIDATION_SPLIT, DEFAULT_TEST_SPLIT, DEFAULT_SEED)
    df["split"] = splits

    conn = _db()
    cur = conn.cursor()

    examples_added = 0
    missing = 0
    bad = 0

    for i, row in df.iterrows():
        rel = row["image_path"].strip().replace("\\", "/")
        label = row["label"].strip()
        split = row["split"]

        try:
            img_path = _resolve_path(bundle_dir, rel)
        except Exception:
            bad += 1
            continue

        if not os.path.exists(img_path) or not os.path.isfile(img_path):
            missing += 1
            continue
        if not _is_image_path(img_path):
            bad += 1
            continue

        ex_id = str(uuid.uuid4())
        created_at = _now_iso()
        cur.execute(
            """
            INSERT INTO examples (id, created_at, contribution_id, label, image_path, split)
            VALUES (?, ?, ?, ?, ?, ?)
            """,
            (ex_id, created_at, contribution_id, label, img_path, split),
        )
        examples_added += 1

    cur.execute(
        "UPDATE contributions SET status=?, message=? WHERE id=?",
        ("ready", f"ingested={examples_added}, missing={missing}, bad={bad}", contribution_id),
    )
    conn.commit()
    conn.close()
    return examples_added, missing, bad


def _get_all_examples() -> pd.DataFrame:
    conn = _db()
    df = pd.read_sql_query(
        "SELECT id, label, image_path, split, contribution_id, created_at FROM examples",
        conn,
    )
    conn.close()
    return df


def _get_classes(df: pd.DataFrame) -> List[str]:
    classes = sorted(df["label"].unique().tolist())
    if len(classes) < 2:
        raise HTTPException(status_code=400, detail="Need at least 2 classes to train.")
    return classes


def _decode_and_resize(path: tf.Tensor, image_size: int) -> tf.Tensor:
    img_bytes = tf.io.read_file(path)
    img = tf.io.decode_image(img_bytes, channels=3, expand_animations=False)
    img = tf.image.resize(img, [image_size, image_size], method=tf.image.ResizeMethod.BILINEAR)
    img = tf.cast(img, tf.float32) / 255.0
    return img


def _make_dataset(df: pd.DataFrame, classes: List[str], image_size: int, batch_size: int, training: bool) -> tf.data.Dataset:
    label_to_idx = {c: i for i, c in enumerate(classes)}
    paths = df["image_path"].astype(str).tolist()
    labels = [label_to_idx[lbl] for lbl in df["label"].astype(str).tolist()]

    ds = tf.data.Dataset.from_tensor_slices((paths, labels))

    def _map_fn(p, y):
        x = _decode_and_resize(p, image_size)
        return x, tf.one_hot(y, depth=len(classes), dtype=tf.float32)

    if training:
        ds = ds.shuffle(min(len(paths), 2000), seed=DEFAULT_SEED, reshuffle_each_iteration=True)

    autotune = tf.data.AUTOTUNE
    ds = ds.map(_map_fn, num_parallel_calls=autotune)
    if training:
        aug = tf.keras.Sequential(
            [
                tf.keras.layers.RandomFlip("horizontal"),
                tf.keras.layers.RandomRotation(0.05),
                tf.keras.layers.RandomZoom(0.1),
                tf.keras.layers.RandomContrast(0.1),
            ]
        )

        def _aug(x, y):
            return aug(x, training=True), y

        ds = ds.map(_aug, num_parallel_calls=autotune)

    ds = ds.batch(batch_size).prefetch(autotune)
    return ds


def _build_model(num_classes: int, image_size: int, base: str = "MobileNetV2") -> tf.keras.Model:
    if base == "MobileNetV2":
        backbone = tf.keras.applications.MobileNetV2(
            input_shape=(image_size, image_size, 3),
            include_top=False,
            weights="imagenet",
        )
        preprocess = tf.keras.applications.mobilenet_v2.preprocess_input
    elif base == "EfficientNetB0":
        backbone = tf.keras.applications.EfficientNetB0(
            input_shape=(image_size, image_size, 3),
            include_top=False,
            weights="imagenet",
        )
        preprocess = tf.keras.applications.efficientnet.preprocess_input
    else:
        raise HTTPException(status_code=400, detail="Unsupported base_model")

    backbone.trainable = False

    inputs = tf.keras.Input(shape=(image_size, image_size, 3), dtype=tf.float32)
    x = tf.keras.layers.Lambda(preprocess)(inputs)
    x = backbone(x, training=False)
    x = tf.keras.layers.GlobalAveragePooling2D()(x)
    x = tf.keras.layers.Dropout(0.2)(x)
    outputs = tf.keras.layers.Dense(num_classes, activation="softmax")(x)
    model = tf.keras.Model(inputs, outputs)
    return model


def _fine_tune(model: tf.keras.Model, base_model_name: str, fine_tune_at: int = -30) -> None:
    backbone = None
    for layer in model.layers:
        if isinstance(layer, tf.keras.Model):
            backbone = layer
            break
    if backbone is None:
        for l in model.layers:
            if hasattr(l, "layers"):
                backbone = l
                break
    if backbone is None:
        return

    backbone.trainable = True
    if fine_tune_at < 0:
        fine_tune_at = max(0, len(backbone.layers) + fine_tune_at)
    for l in backbone.layers[:fine_tune_at]:
        l.trainable = False


def _save_model_version(model: tf.keras.Model, classes: List[str], metrics: Dict[str, Any], image_size: int, base_model: str) -> str:
    version_id = str(uuid.uuid4())
    out_dir = os.path.join(EXPORTS_DIR, version_id)
    _safe_mkdir(out_dir)
    model.save(out_dir, include_optimizer=False)

    conn = _db()
    conn.execute(
        """
        INSERT INTO model_versions (id, created_at, saved_model_dir, metrics_json, classes_json, image_size, base_model)
        VALUES (?, ?, ?, ?, ?, ?, ?)
        """,
        (
            version_id,
            _now_iso(),
            out_dir,
            json.dumps(metrics or {}),
            json.dumps(classes),
            int(image_size),
            base_model,
        ),
    )
    conn.commit()
    conn.close()

    try:
        if os.path.islink(MODEL_DIR) or os.path.exists(MODEL_DIR):
            if os.path.islink(MODEL_DIR):
                os.unlink(MODEL_DIR)
            else:
                shutil.rmtree(MODEL_DIR, ignore_errors=True)
        shutil.copytree(out_dir, MODEL_DIR)
    except Exception:
        pass

    return version_id


def _latest_model_info() -> Optional[Dict[str, Any]]:
    conn = _db()
    cur = conn.cursor()
    cur.execute("SELECT id, created_at, saved_model_dir, metrics_json, classes_json, image_size, base_model FROM model_versions ORDER BY created_at DESC LIMIT 1")
    row = cur.fetchone()
    conn.close()
    if not row:
        return None
    return {
        "id": row[0],
        "created_at": row[1],
        "saved_model_dir": row[2],
        "metrics": json.loads(row[3] or "{}"),
        "classes": json.loads(row[4] or "[]"),
        "image_size": int(row[5]),
        "base_model": row[6],
    }


def _train_job(
    job_id: str,
    epochs: int,
    batch_size: int,
    image_size: int,
    lr: float,
    base_model: str,
    fine_tune: bool,
) -> Dict[str, Any]:
    df = _get_all_examples()
    if df.empty:
        raise HTTPException(status_code=400, detail="No training examples available.")

    classes = _get_classes(df)

    train_df = df[df["split"] == "train"].copy()
    val_df = df[df["split"] == "val"].copy()
    test_df = df[df["split"] == "test"].copy()

    if train_df.empty:
        raise HTTPException(status_code=400, detail="No train split examples.")
    if val_df.empty:
        val_df = train_df.sample(frac=min(0.15, max(1.0 / len(train_df), 0.0)), random_state=DEFAULT_SEED).copy()

    train_ds = _make_dataset(train_df, classes, image_size, batch_size, training=True)
    val_ds = _make_dataset(val_df, classes, image_size, batch_size, training=False)
    test_ds = _make_dataset(test_df, classes, image_size, batch_size, training=False) if not test_df.empty else None

    model = _build_model(num_classes=len(classes), image_size=image_size, base=base_model)
    model.compile(
        optimizer=tf.keras.optimizers.Adam(learning_rate=lr),
        loss=tf.keras.losses.CategoricalCrossentropy(label_smoothing=0.0),
        metrics=[
            tf.keras.metrics.CategoricalAccuracy(name="acc"),
            tf.keras.metrics.TopKCategoricalAccuracy(k=min(5, len(classes)), name="topk"),
        ],
    )

    callbacks = [
        tf.keras.callbacks.ModelCheckpoint(
            filepath=os.path.join(CHECKPOINT_DIR, "best.keras"),
            monitor="val_acc",
            mode="max",
            save_best_only=True,
            save_weights_only=False,
        ),
        tf.keras.callbacks.EarlyStopping(monitor="val_acc", mode="max", patience=3, restore_best_weights=True),
    ]

    history1 = model.fit(train_ds, validation_data=val_ds, epochs=max(1, epochs), callbacks=callbacks, verbose=0)

    if fine_tune:
        _fine_tune(model, base_model)
        model.compile(
            optimizer=tf.keras.optimizers.Adam(learning_rate=lr * 0.1),
            loss=tf.keras.losses.CategoricalCrossentropy(label_smoothing=0.0),
            metrics=[
                tf.keras.metrics.CategoricalAccuracy(name="acc"),
                tf.keras.metrics.TopKCategoricalAccuracy(k=min(5, len(classes)), name="topk"),
            ],
        )
        history2 = model.fit(train_ds, validation_data=val_ds, epochs=max(1, max(2, epochs // 2)), callbacks=callbacks, verbose=0)
    else:
        history2 = None

    eval_val = model.evaluate(val_ds, verbose=0)
    metrics = dict(zip(model.metrics_names, [float(x) for x in eval_val]))

    test_metrics = None
    if test_ds is not None:
        eval_test = model.evaluate(test_ds, verbose=0)
        test_metrics = dict(zip(model.metrics_names, [float(x) for x in eval_test]))

    full_metrics = {
        "val": metrics,
        "test": test_metrics,
        "classes": classes,
        "counts": {
            "total": int(len(df)),
            "train": int(len(train_df)),
            "val": int(len(val_df)),
            "test": int(len(test_df)),
        },
        "history": {
            "phase1": {k: [float(v) for v in vals] for k, vals in (history1.history or {}).items()},
            "phase2": {k: [float(v) for v in vals] for k, vals in (history2.history or {}).items()} if history2 else None,
        },
        "job_id": job_id,
        "trained_at": _now_iso(),
        "image_size": int(image_size),
        "batch_size": int(batch_size),
        "epochs": int(epochs),
        "learning_rate": float(lr),
        "base_model": base_model,
        "fine_tune": bool(fine_tune),
    }

    version_id = _save_model_version(model, classes, full_metrics, image_size=image_size, base_model=base_model)
    full_metrics["model_version"] = version_id
    return full_metrics


class TrainRequest(BaseModel):
    epochs: int = DEFAULT_EPOCHS
    batch_size: int = DEFAULT_BATCH_SIZE
    image_size: int = DEFAULT_IMAGE_SIZE
    learning_rate: float = DEFAULT_LR
    base_model: str = "MobileNetV2"
    fine_tune: bool = True


@app.get("/health")
def health():
    info = _latest_model_info()
    return {
        "ok": True,
        "time": _now_iso(),
        "train_state": TRAIN_STATUS["state"],
        "latest_model": {"id": info["id"], "created_at": info["created_at"]} if info else None,
    }


@app.post("/upload")
async def upload_contribution(
    csv_file: UploadFile = File(...),
    images_zip: UploadFile = File(...),
    contributor: Optional[str] = Form(default=None),
):
    if not csv_file.filename.lower().endswith(".csv"):
        raise HTTPException(status_code=400, detail="csv_file must be a .csv")
    if not images_zip.filename.lower().endswith(".zip"):
        raise HTTPException(status_code=400, detail="images_zip must be a .zip")

    csv_bytes = await csv_file.read()
    zip_bytes = await images_zip.read()
    _check_upload_size(csv_bytes)
    _check_upload_size(zip_bytes)

    contribution_id = str(uuid.uuid4())
    created_at = _now_iso()

    contrib_dir = os.path.join(DATA_DIR, "contributions", contribution_id)
    bundle_dir = os.path.join(contrib_dir, "bundle")
    _safe_mkdir(contrib_dir)
    _safe_mkdir(bundle_dir)

    csv_path = os.path.join(contrib_dir, "labels.csv")
    _save_bytes(csv_path, csv_bytes)
    _extract_zip_to_dir(zip_bytes, bundle_dir)

    conn = _db()
    conn.execute(
        """
        INSERT INTO contributions (id, created_at, contributor, source_filename, csv_path, status, message)
        VALUES (?, ?, ?, ?, ?, ?, ?)
        """,
        (contribution_id, created_at, contributor, csv_file.filename, csv_path, "processing", None),
    )
    conn.commit()
    conn.close()

    try:
        added, missing, bad = _ingest_contribution(contribution_id, csv_path, bundle_dir)
    except HTTPException:
        conn = _db()
        conn.execute("UPDATE contributions SET status=?, message=? WHERE id=?", ("error", "failed to ingest CSV/zip", contribution_id))
        conn.commit()
        conn.close()
        raise

    return {
        "contribution_id": contribution_id,
        "created_at": created_at,
        "status": "ready",
        "counts": {"added": added, "missing": missing, "bad": bad},
        "note": "CSV must reference image paths inside the zip; required columns: image_path,label",
    }


@app.get("/contributions")
def list_contributions(limit: int = 50, offset: int = 0):
    limit = max(1, min(200, int(limit)))
    offset = max(0, int(offset))
    conn = _db()
    rows = conn.execute(
        "SELECT id, created_at, contributor, source_filename, status, message FROM contributions ORDER BY created_at DESC LIMIT ? OFFSET ?",
        (limit, offset),
    ).fetchall()
    conn.close()
    return [
        {
            "id": r[0],
            "created_at": r[1],
            "contributor": r[2],
            "source_filename": r[3],
            "status": r[4],
            "message": r[5],
        }
        for r in rows
    ]


@app.get("/examples/stats")
def examples_stats():
    df = _get_all_examples()
    if df.empty:
        return {"total": 0, "by_label": {}, "by_split": {}}
    by_label = df.groupby("label").size().sort_values(ascending=False).to_dict()
    by_split = df.groupby("split").size().to_dict()
    return {"total": int(len(df)), "by_label": {k: int(v) for k, v in by_label.items()}, "by_split": {k: int(v) for k, v in by_split.items()}}


@app.post("/train")
def start_train(req: TrainRequest, background: BackgroundTasks):
    if req.epochs < 1 or req.epochs > 200:
        raise HTTPException(status_code=400, detail="epochs out of range")
    if req.batch_size < 1 or req.batch_size > 512:
        raise HTTPException(status_code=400, detail="batch_size out of range")
    if req.image_size < 32 or req.image_size > 1024:
        raise HTTPException(status_code=400, detail="image_size out of range")
    if req.learning_rate <= 0 or req.learning_rate > 1:
        raise HTTPException(status_code=400, detail="learning_rate out of range")
    if req.base_model not in {"MobileNetV2", "EfficientNetB0"}:
        raise HTTPException(status_code=400, detail="base_model must be MobileNetV2 or EfficientNetB0")

    with TRAIN_LOCK:
        if TRAIN_STATUS["state"] in {"queued", "running"}:
            raise HTTPException(status_code=409, detail="Training already in progress")
        job_id = str(uuid.uuid4())
        TRAIN_STATUS.update(
            {
                "state": "queued",
                "job_id": job_id,
                "started_at": _now_iso(),
                "ended_at": None,
                "message": None,
                "metrics": None,
            }
        )

    def _run():
        with TRAIN_LOCK:
            TRAIN_STATUS["state"] = "running"
            TRAIN_STATUS["message"] = "training"
        try:
            metrics = _train_job(
                job_id=job_id,
                epochs=int(req.epochs),
                batch_size=int(req.batch_size),
                image_size=int(req.image_size),
                lr=float(req.learning_rate),
                base_model=req.base_model,
                fine_tune=bool(req.fine_tune),
            )
            with TRAIN_LOCK:
                TRAIN_STATUS["state"] = "completed"
                TRAIN_STATUS["ended_at"] = _now_iso()
                TRAIN_STATUS["message"] = "completed"
                TRAIN_STATUS["metrics"] = metrics
                TRAIN_STATUS["last_model_version"] = metrics.get("model_version")
        except Exception as e:
            with TRAIN_LOCK:
                TRAIN_STATUS["state"] = "error"
                TRAIN_STATUS["ended_at"] = _now_iso()
                TRAIN_STATUS["message"] = str(e)
                TRAIN_STATUS["metrics"] = None

    background.add_task(_run)
    return {"job_id": job_id, "state": TRAIN_STATUS["state"]}


@app.get("/train/status")
def train_status():
    with TRAIN_LOCK:
        return dict(TRAIN_STATUS)


@app.get("/model/latest")
def model_latest():
    info = _latest_model_info()
    if not info:
        raise HTTPException(status_code=404, detail="No model available yet")
    return info


@app.post("/predict")
async def predict(image: UploadFile = File(...), top_k: int = 5):
    top_k = max(1, min(20, int(top_k)))
    info = _latest_model_info()
    if not info or not os.path.exists(info["saved_model_dir"]):
        raise HTTPException(status_code=404, detail="No model available yet")

    img_bytes = await image.read()
    _check_upload_size(img_bytes)

    tmp_id = str(uuid.uuid4())
    tmp_path = os.path.join(UPLOAD_DIR, f"{tmp_id}_{os.path.basename(image.filename or 'image')}")
    _save_bytes(tmp_path, img_bytes)

    try:
        model = tf.keras.models.load_model(info["saved_model_dir"])
        classes = info["classes"]
        image_size = int(info["image_size"])

        x = _decode_and_resize(tf.constant(tmp_path), image_size)
        x = tf.expand_dims(x, axis=0)
        probs = model.predict(x, verbose=0)[0]
        k = min(top_k, len(classes))
        idx = np.argsort(-probs)[:k].tolist()
        preds = [{"label": classes[i], "prob": float(probs[i])} for i in idx]
        return {"predictions": preds, "model_version": info["id"]}
    finally:
        try:
            os.remove(tmp_path)
        except Exception:
            pass


